import{_ as n,o as e,c as a,a2 as i}from"./chunks/framework.DGp-bpT-.js";const m=JSON.parse('{"title":"Organization Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/organizations.md","filePath":"en/guide/organizations.md","lastUpdated":null}'),o={name:"en/guide/organizations.md"};function r(s,t,l,g,d,c){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="organization-management" tabindex="-1">Organization Management <a class="header-anchor" href="#organization-management" aria-label="Permalink to &quot;Organization Management&quot;">​</a></h1><p>SREBot supports a <strong>multi-organization model</strong>: a single user can belong to multiple organizations with different roles in each. This allows you to manage the infrastructure of different teams or projects from a single account.</p><hr><h2 id="creating-an-organization" tabindex="-1">Creating an Organization <a class="header-anchor" href="#creating-an-organization" aria-label="Permalink to &quot;Creating an Organization&quot;">​</a></h2><p>After registration, the first organization is created <strong>automatically</strong> — the user immediately receives the Owner role and can start using the platform.</p><p>To create an <strong>additional</strong> organization:</p><ol><li>Click the current organization name in the top navigation bar — a dropdown will open.</li><li>Click the <strong>«+»</strong> button (or navigate directly to <code>/dashboard/organizations/new</code>).</li><li>Fill in the form: <ul><li><strong>Organization name</strong> — an arbitrary name that will appear in the navigation.</li><li><strong>Language / Region</strong> — <code>RU</code> (Russian) or <code>EN</code> (English).</li></ul></li><li>Click <strong>«Create»</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Billing currency</p><p>The currency is determined by the selected language: <strong>Russian → RUB</strong>, <strong>English → USD</strong>. The currency is fixed at the time of organization creation and <strong>cannot be changed</strong> later.</p></div><p>After creation, you will automatically become the <strong>Owner</strong> of the new organization and will be redirected to its context.</p><hr><h2 id="multi-organization-membership" tabindex="-1">Multi-Organization Membership <a class="header-anchor" href="#multi-organization-membership" aria-label="Permalink to &quot;Multi-Organization Membership&quot;">​</a></h2><p>A user can be a member of any number of organizations, with the role in each one assigned <strong>independently</strong>.</p><p>For example, you might be an Owner in one organization and a Viewer in another.</p><p>All organizations you belong to are displayed in the <strong>navigation bar dropdown</strong>. Each organization has its own isolated space:</p><ul><li><strong>Billing</strong> — a separate balance and payment history.</li><li><strong>Bot tokens</strong> — agent tokens are bound to a specific organization.</li><li><strong>Team</strong> — its own list of members and invitations.</li><li><strong>Incidents</strong> — incident data does not overlap between organizations.</li></ul><hr><h2 id="switching-organizations" tabindex="-1">Switching Organizations <a class="header-anchor" href="#switching-organizations" aria-label="Permalink to &quot;Switching Organizations&quot;">​</a></h2><p>Switching between organizations does not require re-authentication — simply select the desired organization from the list.</p><ol><li>Click the <strong>organization name</strong> in the top navigation bar.</li><li>The dropdown will display all organizations you belong to. The current organization is marked with a <strong>checkmark</strong> (✓).</li><li>Select the desired organization — the dashboard context will refresh: incidents, billing, team, and tokens will be loaded for the selected organization.</li><li>At the bottom of the dropdown, there is a <strong>«Create Organization»</strong> button.</li></ol><div class="tip custom-block"><p class="custom-block-title">Instant switching</p><p>Switching is instant — data is loaded via API without a page reload. The current session is not interrupted.</p></div><hr><h2 id="organization-context" tabindex="-1">Organization Context <a class="header-anchor" href="#organization-context" aria-label="Permalink to &quot;Organization Context&quot;">​</a></h2><p>All data and actions in the dashboard are scoped to the <strong>current organization</strong>. When you switch, the context changes completely:</p><table tabindex="0"><thead><tr><th>Section</th><th>What is included in the context</th></tr></thead><tbody><tr><td><strong>Incidents</strong></td><td>Incident list, analysis details, tool call history</td></tr><tr><td><strong>Billing</strong></td><td>Balance, tariff, transaction history, payment methods</td></tr><tr><td><strong>Team</strong></td><td>Members, roles, pending invitations</td></tr><tr><td><strong>Bot tokens</strong></td><td>Agent tokens for Telegram, Slack, Discord integration</td></tr></tbody></table><h3 id="roles-and-permissions" tabindex="-1">Roles and Permissions <a class="header-anchor" href="#roles-and-permissions" aria-label="Permalink to &quot;Roles and Permissions&quot;">​</a></h3><p>Your access rights are determined by your <strong>membership in the current organization</strong>. If you are an Owner in one organization and a Viewer in another, switching to the latter will grant you only Viewer permissions.</p><p>For more details on roles, see <a href="/docs/en/guide/team-management">Team Management</a>.</p><h3 id="fixed-currency" tabindex="-1">Fixed Currency <a class="header-anchor" href="#fixed-currency" aria-label="Permalink to &quot;Fixed Currency&quot;">​</a></h3><p>The billing currency is set <strong>once</strong> when the organization is created and cannot be changed. If you need a different currency, create a new organization with the desired language/region.</p>',29)])])}const u=n(o,[["render",r]]);export{m as __pageData,u as default};
